from collections import deque
class Solution:
    def minOperations(self, s):
        present = sorted(set(c for c in s if c != 'a'), key=lambda c: ord(c))
        if not present:
            return 0
        # simulate advancing the distinct letter values until all reach 'a'
        state = set(ord(c) - 97 for c in present)
        ops = 0
        while state:
            nxt = set()
            for p in state:
                np = (p + 1) % 26
                if np != 0:
                    nxt.add(np)
            state = nxt
            ops += 1
        return ops

